// ✅ Solution 1: Wait for the loading spinner to disappear
WebDriverWait wait = new WebDriverWait(driver, Duration.ofSeconds(10));
wait.until(ExpectedConditions.invisibilityOfElementLocated(By.id("loading-spinner")));
driver.findElement(By.id("submit")).click();

// ✅ Solution 2: Scroll element slightly to avoid sticky header
WebElement btn = driver.findElement(By.id("submit"));
new Actions(driver).moveToElement(btn).click().perform();

// ⚠️ Solution 3: Force click via JS
JavascriptExecutor js = (JavascriptExecutor) driver;
js.executeScript("arguments[0].click();", btn);
